class Solution:
    def palindromePath(self, n, edges, s, queries):
        # Independent approach: instead of precomputed parent/depth ancestor
        # climbing, run a fresh BFS over the raw adjacency list for every single
        # query to recover the unique tree path from scratch.
        from collections import deque, Counter
        adj = [[] for _ in range(n)]
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)
        chars = list(s)
        result = []
        for q in queries:
            parts = q.split()
            if parts[0] == 'update':
                u = int(parts[1])
                c = parts[2]
                chars[u] = c
            else:
                u = int(parts[1])
                v = int(parts[2])
                if u == v:
                    path = [u]
                else:
                    prev = {u: None}
                    dq = deque([u])
                    while dq:
                        cur = dq.popleft()
                        if cur == v:
                            break
                        for nxt in adj[cur]:
                            if nxt not in prev:
                                prev[nxt] = cur
                                dq.append(nxt)
                    path = []
                    cur = v
                    while cur is not None:
                        path.append(cur)
                        cur = prev[cur]
                cnt = Counter(chars[i] for i in path)
                odd = sum(1 for c in cnt.values() if c % 2 == 1)
                result.append(odd <= 1)
        return result

