var palindromePath = function(n, edges, s, queries) {
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }
    const parent = new Array(n).fill(-1);
    const depth = new Array(n).fill(0);
    const visited = new Array(n).fill(false);
    const root = 0;
    visited[root] = true;
    const queue = [root];
    let qi = 0;
    while (qi < queue.length) {
        const u = queue[qi++];
        for (const v of adj[u]) {
            if (!visited[v]) {
                visited[v] = true;
                parent[v] = u;
                depth[v] = depth[u] + 1;
                queue.push(v);
            }
        }
    }
    const chars = s.split('');

    function pathNodes(u, v) {
        let pu = u, pv = v;
        const ancU = [];
        const ancV = [];
        let du = depth[u], dv = depth[v];
        while (du > dv) { ancU.push(pu); pu = parent[pu]; du--; }
        while (dv > du) { ancV.push(pv); pv = parent[pv]; dv--; }
        while (pu !== pv) { ancU.push(pu); ancV.push(pv); pu = parent[pu]; pv = parent[pv]; }
        const lca = pu;
        return ancU.concat([lca], ancV.slice().reverse());
    }

    const result = [];
    for (const q of queries) {
        const parts = q.split(' ');
        if (parts[0] === 'update') {
            const u = parseInt(parts[1], 10);
            const c = parts[2];
            chars[u] = c;
        } else {
            const u = parseInt(parts[1], 10);
            const v = parseInt(parts[2], 10);
            const nodes = pathNodes(u, v);
            const cnt = new Map();
            for (const idx of nodes) {
                const ch = chars[idx];
                cnt.set(ch, (cnt.get(ch) || 0) + 1);
            }
            let odd = 0;
            for (const c of cnt.values()) {
                if (c % 2 === 1) odd++;
            }
            result.push(odd <= 1);
        }
    }
    return result;
};
